class Solution:
    def minimumAddedCoins(self, coins, target):
        pool = list(coins)
        added = 0
        while True:
            reachable = [False] * (target + 1)
            reachable[0] = True
            for c in pool:
                if c > target:
                    continue
                for v in range(target, c - 1, -1):
                    if reachable[v - c]:
                        reachable[v] = True
            gap = None
            for m in range(1, target + 1):
                if not reachable[m]:
                    gap = m
                    break
            if gap is None:
                return added
            pool.append(gap)
            added += 1

