class Solution:
    def minimumAddedCoins(self, coins, target):
        coins = sorted(coins)
        reach = 0
        i = 0
        n = len(coins)
        added = 0
        while reach < target:
            if i < n and coins[i] <= reach + 1:
                reach += coins[i]
                i += 1
            else:
                reach += reach + 1
                added += 1
        return added

