var minimumAddedCoins = function(coins, target) {
    const sorted = [...coins].sort((a, b) => a - b);
    let reach = 0;
    let i = 0;
    const n = sorted.length;
    let added = 0;
    while (reach < target) {
        if (i < n && sorted[i] <= reach + 1) {
            reach += sorted[i];
            i += 1;
        } else {
            reach += reach + 1;
            added += 1;
        }
    }
    return added;
};
